text:
@breakpoints {
  .rt-IconButton:where(.rt-variant-ghost) {
    &:where(.rt-r-size-1) {
      --icon-button-ghost-padding: var(--space-1);
    }
    &:where(.rt-r-size-2) {
      --icon-button-ghost-padding: calc(var(--space-1) * 1.5);
    }
    &:where(.rt-r-size-3) {
      --icon-button-ghost-padding: var(--space-2);
    }
    &:where(.rt-r-size-4) {
      --icon-button-ghost-padding: var(--space-3);
    }
  }
}

@breakpoints {
  .rt-ScrollAreaScrollbar {
    &:where(.rt-r-size-1) {
      --scrollarea-scrollbar-size: var(--space-1);
      --scrollarea-scrollbar-border-radius: max(var(--radius-1), var(--radius-full));
    }
    &:where(.rt-r-size-2) {
      --scrollarea-scrollbar-size: var(--space-2);
      --scrollarea-scrollbar-border-radius: max(var(--radius-1), var(--radius-full));
    }
    &:where(.rt-r-size-3) {
      --scrollarea-scrollbar-size: var(--space-3);
      --scrollarea-scrollbar-border-radius: max(var(--radius-1), var(--radius-full));
    }
  }
}

&:where(.rt-r-size-1) {
  --segmented-control-border-radius: max(var(--radius-2), var(--radius-full));
  height: var(--space-5);

  & :where(.rt-SegmentedControlItemLabel) {
    font-size: var(--font-size-1);
    letter-spacing: var(--letter-spacing-1);
    padding-left: var(--space-3);
    padding-right: var(--space-3);
    gap: var(--space-1);
  }
}

&:where(.rt-r-size-2) {
  --segmented-control-border-radius: max(var(--radius-2), var(--radius-full));
  height: var(--space-6);

  & :where(.rt-SegmentedControlItemLabel) {
    font-size: var(--font-size-2);
    letter-spacing: var(--letter-spacing-2);
    padding-left: var(--space-4);
    padding-right: var(--space-4);
    gap: var(--space-2);
  }
}

&:where(.rt-r-size-3) {
  --segmented-control-border-radius: max(var(--radius-3), var(--radius-full));
  height: var(--space-7);

  & :where(.rt-SegmentedControlItemLabel) {
    font-size: var(--font-size-3);
    letter-spacing: var(--letter-spacing-3);
    padding-left: var(--space-4);
    padding-right: var(--space-4);
    gap: var(--space-3);
  }
}

& :where(.rt-SliderRange) {
  background-color: var(--accent-track);
  background-image: var(--slider-range-high-contrast-background-image);
  box-shadow:
    inset 0 0 0 1px var(--gray-a3),
    inset 0 0 0 1px var(--accent-a4),
    inset 0 0 0 1px var(--black-a1),
    inset 0 1.5px 2px 0 var(--black-a2);

  &:where(.rt-high-contrast) {
    box-shadow:
      inset 0 0 0 1px var(--gray-a3),
      inset 0 0 0 1px var(--black-a2),
      inset 0 1.5px 2px 0 var(--black-a2);
  }
}

@breakpoints {
  .rt-SwitchRoot {
    &:where(.rt-r-size-1) {
      --switch-height: var(--space-4);
      --switch-border-radius: max(var(--radius-1), var(--radius-thumb));
    }
    &:where(.rt-r-size-2) {
      --switch-height: calc(var(--space-5) * 5 / 6);
      --switch-border-radius: max(var(--radius-2), var(--radius-thumb));
    }
    &:where(.rt-r-size-3) {
      --switch-height: var(--space-5);
      --switch-border-radius: max(var(--radius-2), var(--radius-thumb));
    }
  }
}

[aria-busy=true]:not(input, select, textarea, html, form) {
  white-space: nowrap;
}
[aria-busy=true]:not(input, select, textarea, html, form)::before {
  display: inline-block;
  width: 1em;
  height: 1em;
  background-image: var(--pico-icon-loading);
  background-size: 1em auto;
  background-repeat: no-repeat;
  content: "";
  vertical-align: -0.125em;
}
[aria-busy=true]:not(input, select, textarea, html, form):not(:empty)::before {
  margin-inline-end: calc(var(--pico-spacing) * 0.5);
}

@media (hover: hover) {
  &:where(:hover) {
    &::after {
      background-color: var(--accent-10);
      background-image: linear-gradient(var(--black-a2) -15%, transparent, var(--white-a3));
    }
    &:where(.rt-high-contrast) {
      filter: var(--base-button-classic-high-contrast-hover-filter);
      &::after {
        background-color: var(--accent-12);
        background-image: linear-gradient(var(--black-a5), transparent, var(--white-a2));
      }
    }
  }
}

&:where(:hover) {
  &::after {
    background-color: var(--accent-10);
    background-image: linear-gradient(var(--black-a2) -15%, transparent, var(--white-a3));
  }
  &:where(.rt-high-contrast) {
    filter: var(--base-button-classic-high-contrast-hover-filter);
    &::after {
      background-color: var(--accent-12);
      background-image: linear-gradient(var(--black-a5), transparent, var(--white-a2));
    }
  }
}

&:where([data-state='open']) {
  &::after {
    background-color: var(--accent-10);
    background-image: linear-gradient(var(--black-a2) -15%, transparent, var(--white-a3));
  }
  &:where(.rt-high-contrast) {
    filter: var(--base-button-classic-high-contrast-hover-filter);
    &::after {
      background-color: var(--accent-12);
      background-image: linear-gradient(var(--black-a5), transparent, var(--white-a2));
    }
  }
}

&:where([data-disabled]) {
  color: var(--gray-a8);
  background-color: var(--gray-2);
  background-image: none;
  box-shadow: var(--base-button-classic-disabled-box-shadow);
  outline: none;
  filter: none;

  &::after {
    box-shadow: none;
    background-color: var(--gray-a2);
    background-image: linear-gradient(var(--black-a1) -20%, transparent, var(--white-a1));
  }
}

&:where(.rt-r-size-1) {
  gap: var(--space-1);
  font-size: var(--font-size-1);
  line-height: var(--line-height-1);
  letter-spacing: var(--letter-spacing-1);

  &:where(:not(.rt-variant-ghost)) {
    padding-left: var(--space-2);
    padding-right: var(--space-2);
  }
  &:where(.rt-variant-ghost) {
    gap: var(--space-1);
    --button-ghost-padding-x: var(--space-2);
    --button-ghost-padding-y: var(--space-1);
  }
}

&:where(.rt-r-size-2) {
  gap: var(--space-2);
  font-size: var(--font-size-2);
  line-height: var(--line-height-2);
  letter-spacing: var(--letter-spacing-2);

  &:where(:not(.rt-variant-ghost)) {
    padding-left: var(--space-3);
    padding-right: var(--space-3);
  }
  &:where(.rt-variant-ghost) {
    gap: var(--space-1);
    --button-ghost-padding-x: var(--space-2);
    --button-ghost-padding-y: var(--space-1);
  }
}

&:where(.rt-r-size-3) {
  gap: var(--space-3);
  font-size: var(--font-size-3);
  line-height: var(--line-height-3);
  letter-spacing: var(--letter-spacing-3);

  &:where(:not(.rt-variant-ghost)) {
    padding-left: var(--space-4);
    padding-right: var(--space-4);
  }
  &:where(.rt-variant-ghost) {
    gap: var(--space-2);
    --button-ghost-padding-x: var(--space-3);
    --button-ghost-padding-y: calc(var(--space-1) * 1.5);
  }
}

&:where(.rt-r-size-4) {
  gap: var(--space-3);
  font-size: var(--font-size-4);
  line-height: var(--line-height-4);
  letter-spacing: var(--letter-spacing-4);

  &:where(:not(.rt-variant-ghost)) {
    padding-left: var(--space-5);
    padding-right: var(--space-5);
  }
  &:where(.rt-variant-ghost) {
    gap: var(--space-2);
    --button-ghost-padding-x: var(--space-4);
    --button-ghost-padding-y: var(--space-2);
  }
}

@breakpoints {
  .rt-ContainerInner {
    :where(.rt-Container.rt-r-size-1) > & {
      max-width: var(--container-1);
    }
    :where(.rt-Container.rt-r-size-2) > & {
      max-width: var(--container-2);
    }
    :where(.rt-Container.rt-r-size-3) > & {
      max-width: var(--container-3);
    }
    :where(.rt-Container.rt-r-size-4) > & {
      max-width: var(--container-4);
    }
  }
}

@breakpoints {
  .rt-HoverCardContent {
    &:where(.rt-r-size-1) {
      --hover-card-content-padding: var(--space-3);
      border-radius: var(--radius-4);
    }
    &:where(.rt-r-size-2) {
      --hover-card-content-padding: var(--space-4);
      border-radius: var(--radius-4);
    }
    &:where(.rt-r-size-3) {
      --hover-card-content-padding: var(--space-5);
      border-radius: var(--radius-5);
    }
  }
}

body {
	--spectrum-font-family: var(--spectrum-sans-font-family-stack);
	--spectrum-font-style: var(--spectrum-default-font-style);
	--spectrum-font-size: var(--spectrum-font-size-100);

	margin: 0;

	font-family: var(--spectrum-font-family);
	font-size: var(--spectrum-font-size);
	font-style: var(--spectrum-font-style);

	color: var(--spectrum-neutral-content-color-default, rgb(34, 34, 34));
	background-color: var(--spectrum-background-base-color, rgb(230, 230, 230));
}

&.spectrum-Button--iconOnly {
	min-inline-size: unset;
	padding: calc(var(--mod-button-edge-to-visual-only, var(--spectrum-button-edge-to-visual-only)) - var(--mod-button-border-width, var(--spectrum-button-border-width)));
	border-radius: 50%;

	.spectrum-Icon {
		align-self: center;
		margin-inline-start: 0;
		margin-block-start: 0;
	}

	&::after {
		border-radius: 50%;
	}
}

&.is-selected {
  border-color: var(--spectrum-card-border-color-key-focus);
  &:after {
    background-color: var(--spectrum-global-color-blue-400);
    opacity: 0.15;
  }
  &:hover {
    border-color: var(--spectrum-card-border-color-key-focus);
    &:after {
      background-color: var(--spectrum-global-color-blue-400);
      opacity: 0.25;
    }
  }
}

&:after {
  border-radius: calc(var(--spectrum-focus-ring-border-radius) + var(--spectrum-focus-ring-gap));
  content: '';
  display: block;
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  top: 0;
  margin: calc(-1 * var(--spectrum-focus-ring-border-size));
  pointer-events: none;

  transition:
    box-shadow var(--spectrum-global-animation-duration-100) ease-out,
    margin var(--spectrum-global-animation-duration-100) ease-out;
}

&.is-range-end,
		&.is-selection-end {
			inline-size: calc(var(--spectrum-calendar-day-width) + var(--spectrum-calendar-day-padding));
			padding-inline-start: var(--spectrum-calendar-day-padding);
			margin-inline-end: var(--spectrum-calendar-day-padding);

			border-start-end-radius: var(--spectrum-calendar-day-width);
			border-end-end-radius: var(--spectrum-calendar-day-width);

			&::before,
			&::after {
				inset-inline-start: auto;
				inset-inline-end: 0;
			}
		}

body,
:host {
  margin: 0;
  font-family: var(--mantine-font-family);
  font-size: var(--mantine-font-size-md);
  line-height: var(--mantine-line-height);
  background-color: var(--mantine-color-body);
  color: var(--mantine-color-text);

  -webkit-font-smoothing: var(--mantine-webkit-font-smoothing);
  -moz-osx-font-smoothing: var(--mantine-moz-font-smoothing);

  @media screen and (max-device-width: em(500px)) {
    -webkit-text-size-adjust: 100%;
  }
}

@keyframes dialog-closing {
  from {
    transform: translate(-50%, -50%) scale(calc(pow(0.95, var(--nested-dialogs))))
      translateY(calc(-30px * var(--nested-dialogs)));
    opacity: 1;
    visibility: visible;
  }

  to {
    transform: translate(-50%, -35%) scale(0.8, calc(pow(0.95, var(--nested-dialogs))))
      translateY(calc(-30px * var(--nested-dialogs)));
    opacity: 0.5;
    visibility: hidden;
  }
}

[type=range]:active, [type=range]:focus-within {
  --pico-range-border-color: var(--pico-range-active-border-color);
  --pico-range-thumb-color: var(--pico-range-thumb-active-color);
}
[type=range]:active::-webkit-slider-thumb {
  transform: scale(1.25);
}
[type=range]:active::-moz-range-thumb {
  transform: scale(1.25);
}
[type=range]:active::-ms-thumb {
  transform: scale(1.25);
}

&::after {
	content: "";
	inset-inline: calc(50% - calc(var(--mod-colorhandle-hitarea-size, var(--spectrum-color-control-track-width)) / 2));
	inset-block: calc(50% - calc(var(--mod-colorhandle-hitarea-size, var(--spectrum-color-control-track-width)) / 2));
	position: absolute;
	display: block;
	inline-size: var(--mod-colorhandle-hitarea-size, var(--spectrum-color-control-track-width));
	block-size: var(--mod-colorhandle-hitarea-size, var(--spectrum-color-control-track-width));
	border-radius: var(--mod-colorhandle-hitarea-border-radius, 100%);
}

&:not(.spectrum-Swatch--rectangle) {
	&,
	&::before,
	&::after,
	.spectrum-Swatch-fill,
	.spectrum-Swatch-fill::before,
	&.is-selected .spectrum-Swatch-fill,
	&.is-selected .spectrum-Swatch-fill::before {
		border-radius: 100%;
	}

	&.is-selected .spectrum-Swatch-fill {
		clip-path: circle(calc(50% - (var(--mod-swatch-border-thickness-selected, var(--spectrum-swatch-border-thickness-selected)) * 2)) at 50% 50%);
	}
}

&::after {
	border-radius: calc(calc(var(--mod-switch-control-height, var(--spectrum-switch-control-height)) / 2) + var(--mod-focus-indicator-gap, var(--spectrum-focus-indicator-gap)) * 2);
	content: "";
	display: block;
	position: absolute;
	inset-inline-start: 0;
	inset-inline-end: 0;
	inset-block-end: 0;
	inset-block-start: 0;
	margin: 0;

	transition:
		opacity var(--mod-animation-duration-100, var(--spectrum-animation-duration-100)) ease-out,
		margin var(--spectrum-animation-duration-100, var(--spectrum-animation-duration-100)) ease-out;
}

&:after {
  position: absolute;
  top: calc(50% - calc(var(--spectrum-calendar-day-width) / 2));
  left: calc(50% - calc(var(--spectrum-calendar-day-width) / 2));

  display: block;

  height: var(--spectrum-calendar-day-height);
  width: var(--spectrum-calendar-day-width);

  border-radius: var(--spectrum-calendar-day-width);

  content: '';
  z-index: -1;
}

@keyframes pulse {
  0% {
    -webkit-transform: scale(var(--spectrum-coachmark-animation-indicator-keyframe-0-scale));
    opacity: var(--spectrum-coachmark-animation-indicator-keyframe-0-opacity);
  }
  50% {
    -webkit-transform: scale(var(--spectrum-coachmark-animation-indicator-keyframe-50-scale));
    opacity: var(--spectrum-coachmark-animation-indicator-keyframe-50-opacity);
  }
  100% {
    -webkit-transform: scale(var(--spectrum-coachmark-animation-indicator-keyframe-100-scale));
    opacity: var(--spectrum-coachmark-animation-indicator-keyframe-100-opacity);
  }
}

@keyframes pulse--quiet {
  0% {
    -webkit-transform: scale(var(--spectrum-coachmark-quiet-animation-indicator-keyframe-0-scale));
    opacity: var(--spectrum-coachmark-animation-indicator-keyframe-0-opacity);
  }
  50% {
    -webkit-transform: scale(var(--spectrum-coachmark-animation-indicator-keyframe-50-scale));
    opacity: var(--spectrum-coachmark-animation-indicator-keyframe-50-opacity);
  }
  100% {
    -webkit-transform: scale(var(--spectrum-coachmark-animation-indicator-keyframe-100-scale));
    opacity: var(--spectrum-coachmark-animation-indicator-keyframe-100-opacity);
  }
}

body {
	--spectrum-font-family-ar: myriad-arabic, adobe-clean, "Source Sans Pro", -apple-system, blinkmacsystemfont, "Segoe UI", roboto, ubuntu, "Trebuchet MS", "Lucida Grande", sans-serif;
	--spectrum-font-family-he: myriad-hebrew, adobe-clean, "Source Sans Pro", -apple-system, blinkmacsystemfont, "Segoe UI", roboto, ubuntu, "Trebuchet MS", "Lucida Grande", sans-serif;

	--spectrum-font-family: var(--spectrum-sans-font-family-stack);
	--spectrum-font-style: var(--spectrum-default-font-style);
	--spectrum-font-size: var(--spectrum-font-size-100);

	margin: 0;

	font-family: var(--spectrum-font-family);
	font-size: var(--spectrum-font-size);
	font-style: var(--spectrum-font-style);
}

@container style(--system: legacy) {
	.spectrum-InfieldButton {
		--spectrum-infield-button-background-color: var(--spectrum-gray-75);
		--spectrum-infield-button-background-color-hover: var(--spectrum-gray-200);
		--spectrum-infield-button-background-color-down: var(--spectrum-gray-300);
		--spectrum-infield-button-background-color-key-focus: var(--spectrum-gray-200);

		&:disabled {
			--spectrum-infield-button-border-color: var(--spectrum-gray-200);
		}
	}
}
